	@Test
	void parseCoversFieldCommentsFallbackMetadataAndBooleanHelpers() {
		CreateTemplateConfig template = parse("fallback-template", String.join("\n",
				"[] config:rep.id \"{%Identifier%}\" ;",
				"# @workbench.field control=radio",
				"   rdfs:label \"{%Title%}\" ;",
				"# @workbench.field len=12",
				"   config:description \"{%Description%}\" ;",
				"# @workbench.field rows=2 cols=9",
				"   config:enabled \"{%Enabled|true|false%}\" ;",
				"   config:enabled-label \"{%Enabled%}\" ."));

		assertThat(template.getLabel()).isEqualTo("fallback-template");
		assertThat(template.getOrder()).isEqualTo(Integer.MAX_VALUE);
		assertThat(template.isHidden()).isFalse();
		assertThat(field(template, "Identifier").getControl()).isEqualTo(CreateTemplateConfig.FieldControl.RADIO);
		assertThat(field(template, "Title").getSize()).isEqualTo(12);
		assertThat(field(template, "Description").getRows()).isEqualTo(2);
		assertThat(field(template, "Description").getCols()).isEqualTo(9);
		assertThat(field(template, "Enabled").getControl()).isEqualTo(CreateTemplateConfig.FieldControl.RADIO);
		assertThat(field(template, "Enabled").getRole()).isEmpty();
		assertThat(field(template, "Enabled").getId()).isEqualTo("config_enabled");
		assertThat(invokeBoolean("isBooleanOptions", new Class<?>[] { List.class }, List.of("TRUE", "false"))).isTrue();
		assertThat(invokeInt("defaultRows", new Class<?>[] { CreateTemplateConfig.FieldControl.class },
				CreateTemplateConfig.FieldControl.TEXTAREA)).isEqualTo(8);
		assertThat(invokeInt("defaultCols", new Class<?>[] { CreateTemplateConfig.FieldControl.class },
				CreateTemplateConfig.FieldControl.TEXTAREA)).isEqualTo(80);
		assertThat(invokeString("propertyToId", new Class<?>[] { String.class }, "config:---"))
				.isEqualTo("config_field");
		Map<String, Integer> ids = new LinkedHashMap<>();
		assertThat(invokeString("uniqueId", new Class<?>[] { String.class, Map.class }, "config_enabled", ids))
				.isEqualTo("config_enabled");
		assertThat(invokeString("uniqueId", new Class<?>[] { String.class, Map.class }, "config_enabled", ids))
				.isEqualTo("config_enabled-2");
	}

